// Spiral Star Spinner — a flat, wide star/cog profile extruded over a SHORT
// height with a big twist so its many points sweep around into a low, broad
// spiral bloom (a "spiral galaxy" of star points) around a thin center post.
const { Manifold, CrossSection } = api;

const p = api.params({
  points:   { type: 'int',    default: 12,  min: 8,  max: 14, label: 'Star points' },
  twist:    { type: 'number', default: 240, min: 120, max: 360, step: 5, unit: '°', label: 'Total twist' },
  radius:   { type: 'number', default: 26,  min: 16, max: 32, step: 1, unit: 'mm', label: 'Star radius' },
  height:   { type: 'number', default: 0.28, min: 0.18, max: 0.4, step: 0.02, label: 'Bloom height (×radius)' },
});

// --- Star / cog cross-section: alternating tip + valley radii. Shallow valleys
// keep the points broad and blade-like so the spiral fan reads as overlapping
// fanned blades rather than spindly spikes. ---
const tipR    = p.radius;          // outer points
const valleyR = p.radius * 0.62;   // inner notch radius (shallow -> blade-like)
const verts = [];
const n = p.points;
for (let i = 0; i < n; i++) {
  const aTip    = (i / n) * Math.PI * 2;
  const aValley = ((i + 0.5) / n) * Math.PI * 2;
  verts.push([tipR    * Math.cos(aTip),    tipR    * Math.sin(aTip)]);
  verts.push([valleyR * Math.cos(aValley), valleyR * Math.sin(aValley)]);
}
const starCS = CrossSection.ofPolygons([verts]);

// --- Bloom: extrude the star over a SHORT height with a large twist so the
// points spiral around as they rise -> a flat, wide fanned disc. scaleTop slightly
// >1 fans the points OUTWARD as they sweep, like a spiral galaxy opening up.
// High nDiv keeps the helix smooth across the short rise (no facets). ---
const bloomH = p.radius * p.height;          // flat: ~0.28·radius, not a drum
const bloom = Manifold.extrude(starCS, bloomH, 128, p.twist, 1.12)
  .translate([0, 0, 0]);

// --- Base disc: a thin foot the bloom blossoms out of, hidden under the center
// so the bloom appears to float as a free spiral disc. Overlaps the bloom. ---
const baseR = p.radius * 0.5;
const base = Manifold.cylinder(bloomH * 0.6, baseR, baseR);

// --- Central post: a SLENDER spin axis through the center. Sits low and thin so
// it's a spin pivot, not a dominating handle. Pokes just above the bloom. ---
const postR = p.radius * 0.07;               // thin: ~7% of radius
const postH = bloomH + p.radius * 0.18;      // just clears the bloom top
const post = Manifold.cylinder(postH, postR, postR)
  .translate([0, 0, 0]);

// Tiny rounded cap on the pivot tip — a finishing touch, not a knob.
const cap = Manifold.sphere(postR * 1.1)
  .translate([0, 0, postH]);

const body = api.labeledUnion([
  { name: 'base',  shape: base,            color: '#2e8b8b' },
  { name: 'bloom', shape: bloom,           color: '#43c463' },
  { name: 'post',  shape: post.add(cap),   color: '#f4a52b' },
]);

return body;

